+        const has_unknown_element = switch (var_type) {
+            .list => |elem| elem.* == .unknown,
+            .dict => |kv| kv.value.* == .unknown,
+            else => false,
+        };
+        if (has_unknown_element) {
+            try self.emit(": @TypeOf(");
+            if (self.var_renames.get(var_name)) |renamed| {
+                try self.emit(renamed);
+            } else {
